'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Bot, CheckCircle2, Circle, Clock, KanbanSquare, Loader2, Play } from 'lucide-react';
import { Project, Phase } from '@shared/types/project';
import { Task } from '@shared/types/task';
import { Badge } from '@/components/ui/badge';
import { BackgroundAnimation } from '@/components/ui/background-animation';

export default function ProjectDashboardPage() {
    const { id } = useParams();
    const [projectData, setProjectData] = useState<{ project: Project, phases: Phase[], tasks: Task[] } | null>(null);
    const [nextAction, setNextAction] = useState<{ next_task: Task | null, reasoning: string } | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let active = true;
        async function fetchDashboard() {
            try {
                const [projectRes, actionRes] = await Promise.all([
                    fetch(`/api/projects/${id}`),
                    fetch(`/api/ai/next-action?project_id=${id}`)
                ]);

                if (!active) return;

                if (projectRes.ok) {
                    const pData = await projectRes.json();
                    setProjectData(pData);
                }

                if (actionRes.ok) {
                    const aData = await actionRes.json();
                    setNextAction(aData);
                }
            } catch (error) {
                console.error("Dashboard failed to load", error);
            } finally {
                if (active) setLoading(false);
            }
        }

        fetchDashboard();
        return () => { active = false; };
    }, [id]);

    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-12 text-muted-foreground">
                <Loader2 className="w-8 h-8 animate-spin" />
            </div>
        );
    }

    if (!projectData) return <div>Project not found.</div>;

    const { project, tasks: initialTasks } = projectData;

    // Load and Merge Local Modifications
    const localUser = typeof window !== 'undefined' ? localStorage.getItem(`workflow_user_tasks_${id}`) : null;
    const localRemoved = typeof window !== 'undefined' ? localStorage.getItem(`workflow_removed_tasks_${id}`) : null;
    const userTasks: Task[] = localUser ? JSON.parse(localUser) : [];
    const removedIds = new Set(localRemoved ? JSON.parse(localRemoved) : []);

    const mergedTasks = [
        ...initialTasks.filter(t => !removedIds.has(t.id)),
        ...userTasks
    ];

    // Calculate Progress Stats based on MERGED set
    const totalTasks = mergedTasks.length;
    const completedTasks = mergedTasks.filter(t => t.status === 'DONE').length;
    const executingTasks = mergedTasks.filter(t => t.status === 'RUNNING').length;
    const readyTasks = mergedTasks.filter(t => t.status === 'READY').length;
    const completionPercentage = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

    return (
        <div className="max-w-6xl mx-auto space-y-8 relative">
            <BackgroundAnimation className="z-[-10]" />
            {/* Header row */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h1 className="text-page-title tracking-tight mb-2 flex items-center gap-3">
                        <span className="text-muted-foreground/40 font-light">WORKFLOW /</span> {project.title}
                        {project.is_demo_project && (
                            <Badge variant="default" className="text-[10px] tracking-[0.2em] uppercase bg-primary/10 text-primary border-primary/20">Read-Only Demo</Badge>
                        )}
                    </h1>
                    <p className="text-muted-foreground max-w-3xl font-light italic">"{project.goal_description}"</p>
                </div>
                <Link
                    href={`/project/${id}/board`}
                    className="inline-flex items-center gap-2 bg-primary text-primary-foreground px-6 py-3 rounded-xl font-black uppercase tracking-widest text-xs hover:opacity-90 transition-all shadow-lg whitespace-nowrap active:scale-95"
                >
                    <KanbanSquare className="w-4 h-4" />
                    Open Workflow Interface
                </Link>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

                {/* Progress Dashboard Column */}
                <div className="col-span-1 md:col-span-1 space-y-6">
                    <Card className="border-border/40 shadow-sm">
                        <CardHeader className="pb-4 bg-muted/20 border-b border-border/40">
                            <CardTitle className="text-sm font-bold uppercase tracking-widest text-muted-foreground">Workflow Completion %</CardTitle>
                        </CardHeader>
                        <CardContent className="pt-6">
                            <div className="flex items-center justify-between mb-4">
                                <span className="text-5xl font-black tracking-tight">{completionPercentage}%</span>
                                <Badge variant="success" className="h-5 px-1.5 text-[9px] font-bold tracking-widest uppercase">SYNCED</Badge>
                            </div>
                            <div className="w-full h-2.5 bg-muted rounded-full overflow-hidden mb-8 border border-border/50">
                                <div
                                    className="h-full bg-primary shadow-[0_0_15px_rgba(var(--primary),0.5)] transition-all duration-1000 ease-out"
                                    style={{ width: `${completionPercentage}%` }}
                                />
                            </div>

                            <div className="space-y-4">
                                <div className="flex justify-between items-center text-xs">
                                    <div className="flex items-center gap-2 font-medium text-muted-foreground">
                                        <div className="w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)] animate-pulse" />
                                        TOTAL WORK ITEMS
                                    </div>
                                    <span className="font-bold">{totalTasks}</span>
                                </div>
                                <div className="flex justify-between items-center text-xs">
                                    <div className="flex items-center gap-2 font-medium text-muted-foreground">
                                        <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]" />
                                        COMPLETED WORK ITEMS
                                    </div>
                                    <span className="font-bold">{completedTasks}</span>
                                </div>
                                <div className="flex justify-between items-center text-xs">
                                    <div className="flex items-center gap-2 font-medium text-muted-foreground">
                                        <div className="w-2 h-2 rounded-full bg-primary" />
                                        IN PROGRESS
                                    </div>
                                    <span className="font-bold">{executingTasks}</span>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* AI Next Best Action Column */}
                <div className="col-span-1 md:col-span-2">
                    <Card className="h-full border-primary/30 shadow-xl overflow-hidden group">
                        <CardHeader className="bg-primary/[0.03] border-b border-primary/10">
                            <div className="flex items-center gap-2 mb-1">
                                <Bot className="w-5 h-5 text-primary" />
                                <span className="text-[10px] font-black tracking-[0.2em] text-primary uppercase">Autonomous Decision Engine</span>
                            </div>
                            <CardTitle className="text-xl font-black">Next Strategic Move</CardTitle>
                        </CardHeader>
                        <CardContent className="pt-6">
                            {!nextAction || !nextAction.next_task ? (
                                <div className="p-8 bg-emerald-500/5 border border-emerald-500/20 rounded-2xl text-emerald-600 flex flex-col items-center text-center gap-4">
                                    <div className="w-12 h-12 rounded-full bg-emerald-500/10 flex items-center justify-center">
                                        <CheckCircle2 className="w-6 h-6" />
                                    </div>
                                    <div>
                                        <p className="font-bold text-lg mb-1">Mission Accomplished</p>
                                        <p className="text-sm opacity-80 max-w-sm">
                                            {nextAction?.reasoning || "All workflow nodes have reached terminal state. Project execution finalized."}
                                        </p>
                                    </div>
                                </div>
                            ) : (
                                <div className="space-y-6">
                                    <div className="p-6 bg-muted/30 rounded-2xl border border-border relative overflow-hidden">
                                        <div className="flex items-start justify-between gap-4 mb-4 relative z-10">
                                            <div>
                                                <Badge variant={nextAction.next_task.task_type === 'AI' ? 'ai' : 'human'} className="mb-2 text-[9px] font-black tracking-widest px-2 py-0.5">
                                                    {nextAction.next_task.task_type} EXECUTION
                                                </Badge>
                                                <h3 className="font-black text-2xl text-foreground tracking-tight leading-tight">{nextAction.next_task.title}</h3>
                                            </div>
                                        </div>
                                        <p className="text-muted-foreground text-sm mb-8 font-light leading-relaxed max-w-xl">
                                            {nextAction.next_task.description}
                                        </p>

                                        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-6 border-t border-border pt-6">
                                            <div className="flex-1">
                                                <span className="text-[10px] font-black uppercase text-primary tracking-widest block mb-2 leading-none">Strategist Reasoning</span>
                                                <p className="text-sm text-foreground/80 italic font-light leading-relaxed">
                                                    "{nextAction.reasoning}"
                                                </p>
                                            </div>
                                            <Link
                                                href={`/project/${id}/task/${nextAction.next_task.id}`}
                                                className="shrink-0 flex items-center gap-3 bg-primary text-primary-foreground px-8 py-3.5 rounded-xl font-black uppercase tracking-widest text-[11px] hover:opacity-90 transition-all shadow-[0_0_30px_rgba(var(--primary),0.2)] active:scale-95 group/btn"
                                            >
                                                <Play className="w-4 h-4 fill-current group-hover/btn:scale-110 transition-transform" />
                                                Start Work Item
                                            </Link>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}
